import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/product_model.dart'; final cartProvider = StateNotifierProvider<CartNotifier, CartState>((ref)=>CartNotifier());
class CartItem { final Product product; int quantity; CartItem({required this.product, this.quantity=1}); }
class CartState { final List<CartItem> items; double get totalAmount => items.fold(0, (s,i)=>s+i.product.unitPrice*i.quantity); CartState({this.items=const[]}); CartState copyWith({List<CartItem>? items}) => CartState(items: items??this.items); }
class CartNotifier extends StateNotifier<CartState> { CartNotifier() : super(CartState()); void addItem(Product p) { final idx = state.items.indexWhere((i)=>i.product.sku==p.sku); if(idx!=-1) { final newItems = [...state.items]; newItems[idx].quantity++; state = state.copyWith(items: newItems); } else { state = state.copyWith(items: [...state.items, CartItem(product: p)]); } } void removeItem(String sku) { state = state.copyWith(items: state.items.where((i)=>i.product.sku!=sku).toList()); } void incrementQuantity(String sku) { final newItems = state.items.map((i)=>i.product.sku==sku?CartItem(product:i.product, quantity:i.quantity+1):i).toList(); state = state.copyWith(items: newItems); } void decrementQuantity(String sku) { final newItems = state.items.map((i)=>i.product.sku==sku && i.quantity>1?CartItem(product:i.product, quantity:i.quantity-1):i).toList(); state = state.copyWith(items: newItems); } void clearCart() => state = CartState(); }
